function autoFormatTime(P){let h=P['value']['replace'](/\D/g,'');switch(h['length']>0x4&&(h=h['slice'](0x0,0x4)),h['length']){case 0x0:case 0x1:case 0x2:P['value']=h;break;case 0x3:if(parseInt(h['slice'](0x0,0x2),0xa)<=0x17)P['value']=h['slice'](0x0,0x2)+':'+h['slice'](0x2);else{let B=h['slice'](0x0,0x1)['padStart'](0x2,'0'),H=h['slice'](0x1);P['value']=B+':'+H;}break;case 0x4:let T=h['slice'](0x0,0x2),N=h['slice'](0x2);P['value']=T+':'+N;}}function transformTimeValue(a){let P=a['trim']();if(/^\d{2}$/['test'](P))return P[0x0]['padStart'](0x2,'0')+':'+P[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](P))return 0x3===P['length']?parseInt(P['slice'](0x0,0x2),0xa)<=0x17?P['slice'](0x0,0x2)+':'+P['slice'](0x2):P['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+P['slice'](0x1):P['slice'](0x0,0x2)+':'+P['slice'](0x2);if(P['includes'](':')){let [h,T]=P['split'](':');return T||(T='00'),h=h['padStart'](0x2,'0'),T=T['padStart'](0x2,'0'),h+':'+T;}return P;}